// sandbox srcdoc 不允许 Shower location 模块写 /srcdoc；start 期间省略 URL 参数并立即恢复 History 方法
import Shower from 'https://cdn.jsdelivr.net/npm/@shower/core@3.6.0/lib/shower.js';
const theme=document.createElement('link'); theme.rel='stylesheet'; theme.href='https://cdn.jsdelivr.net/npm/@shower/ribbon@4/styles/index.css'; document.head.append(theme);
const root=document.getElementById('shower-deck'); root.className='shower list'; root.tabIndex=0; root.innerHTML=data.html;
const shower=new Shower({containerSelector:'#shower-deck'});
const originalReplaceState=history.replaceState, originalPushState=history.pushState;
history.replaceState=(state,title)=>originalReplaceState.call(history,state,title); history.pushState=(state,title)=>originalPushState.call(history,state,title);
try { shower.start(); } finally { history.replaceState=originalReplaceState; history.pushState=originalPushState; }

